mapper.select:
SELECT c.teacher_id, COALESCE(c.teacher_name, u.nick_name, '未知教师') AS teacher_name, s.id AS semester_id, s.semester_name, COALESCE(ROUND(AVG(e.score * 1.0 / NULLIF(q.score, 0) * 10), 1), 0.0) AS avg_score, COUNT(DISTINCT e.id) AS eval_count, COUNT(DISTINCT c.id) AS course_count FROM cou_course c INNER JOIN sys_semester s ON c.semester_id = s.id LEFT JOIN sys_user u ON c.teacher_id = u.user_id LEFT JOIN stu_evaluation e ON e.course_id = c.id AND e.semester_id = c.semester_id LEFT JOIN eva_question q ON e.question_id = q.id WHERE c.del_flag = '0' AND c.teacher_id IS NOT NULL
AND c.semester_id = #{semesterId}
GROUP BY c.teacher_id, c.teacher_name, u.nick_name, s.id, s.semester_name ORDER BY avg_score DESC NULLS LAST, c.teacher_name, s.semester_name

SELECT e.student_id, stu.real_name AS student_name, stu.student_no, cla.class_name, e.course_id, c.course_name, e.question_id, q.content AS question_content, e.score, q.score AS max_score, e.create_time FROM stu_evaluation e INNER JOIN cou_course c ON e.course_id = c.id AND c.del_flag = '0' LEFT JOIN eva_question q ON e.question_id = q.id LEFT JOIN stu_student_info stu ON e.student_id = stu.user_id AND stu.del_flag = '0' LEFT JOIN sys_class cla ON stu.class_id = cla.id WHERE e.semester_id = #{semesterId}
AND c.teacher_id = #{teacherId}
AND c.teacher_name = #{teacherName}
ORDER BY e.create_time DESC

mapper.delete:
DELETE FROM stu_evaluation
WHERE course_id IN (
    SELECT id FROM cou_course
    WHERE teacher_id = #{teacherId}
    AND semester_id = #{semesterId}
    AND del_flag = '0'
)
AND semester_id = #{semesterId}
